#include<bits/stdc++.h>
using namespace std;
int n,m,ans,a[110][110];
string st;
char ch;
const int dx[]={0,0,1,-1,0};
const int dy[]={0,1,0,0,-1};
void dfs(int x,int y)
{
	a[x][y]=0;
	for(int i=1;i<=4;i++)
	{
		if(x+dx[i]<1||x+dx[i]>n||y+dy[i]<0||y+dy[i]>=m||!a[x+dx[i]][y+dy[i]]) continue;
		dfs(x+dx[i],y+dy[i]);
	}
}
int main()
{
	ios::sync_with_stdio(false);
	cin.tie(nullptr),cout.tie(nullptr);
	cin>>n>>m;
	cin.ignore();
	for(int i=1;i<=n;i++)
	{
		getline(cin,st);
		for(int j=0;j<m;j++)
		{
			if(st[j]>'0') a[i][j+1]=1;
		}
	}
	for(int i=1;i<=n;i++)
	{
		for(int j=0;j<m;j++)
		{
			if(a[i][j])
			{
				ans++;
				dfs(i,j);
			}
		}
	}
	cout<<ans;
	return 0;
}
